solution_code:
#include <iostream>
#include <string_view>

enum Color
{
    red   = 0,
    green = 1,
    blue  = 2
};

constexpr std::string_view colorToString(Color c)
{
    switch (c)
    {
        case red:   return "red";
        case green: return "green";
        case blue:  return "blue";
        default:    return "unknown";
    }
}

int main()
{
    int n;
    std::cin >> n;

    for (int i = 0; i < n; ++i)
    {
        int code;
        std::cin >> code;
        std::cout << colorToString(static_cast<Color>(code)) << '\n';
    }

    return 0;
}

